head.script:

scwin.onpageload = function(e) {//debugger;
    const serverMode = window.location.hostname.indexOf("newdevdebis.dongwon.com") > -1 ? "dev" : 
                        window.location.hostname.indexOf("newdebis.dongwon.com") > -1 ? "prd" : "local";
    if (serverMode == "dev") {
        tbx_dev.setStyle("display", "flex");
    } else {
        tbx_dev.hide();
    }

    scwin.coClsCd = WebSquare.localStorage.getItem("coClsCd");
    scwin.privAdmin = WebSquare.localStorage.getItem("privAdmin");
    scwin.coCd = WebSquare.localStorage.getItem("coCd");
    scwin.sysCd = WebSquare.localStorage.getItem("sysCd");
    scwin.userHomeClsCd = WebSquare.localStorage.getItem("userHomeClsCd");
    scwin.userClsCd = WebSquare.localStorage.getItem("userClsCd");
    scwin.menuData = []; // 메뉴 데이터
    scwin.menuInit();

    // 최초 로딩시 좌측 메뉴가져오기    
    dma_userParam.set("coCd", scwin.coCd);
    dma_userParam.set("sysCd", scwin.sysCd);
    dma_userParam.set("userHomeClsCd", scwin.userHomeClsCd);
    dma_userParam.set("userId", WebSquare.localStorage.getItem("userId"));
    if(scwin.userClsCd != "01" && (scwin.userHomeClsCd == "FB" || scwin.userHomeClsCd == "81")){
        dma_userParam.set("systemClsCd", "NTIS");
        dma_userParam.set("sysCd", "NC");
    }
    $c.sbm.execute(sbm_getMenuList);

	// 메뉴  css 관련
    //$(document).ready(function() {
        const storageKey = 'gnbSelectedIndex';
        let selectedIndex = localStorage.getItem(storageKey);

        $(".gnb li").on("mouseenter", function() {
            // 현재 클릭된 메뉴는 유지한 상태에서, 마우스 올린 메뉴에만 임시 on 추가
            $(".gnb li").removeClass("hover");
            $(this).addClass("hover");
        }).on("mouseleave", function() {
            // 마우스 나가면 hover 클래스 제거
            $(this).removeClass("hover");
        }).on("click", function() {
            // 클릭하면 클릭된 메뉴는 on 유지, hover는 초기화
            $(".gnb li").removeClass("on");
            $(".gnb li").removeClass("hover");
            $(this).addClass("on");
            selectedIndex = $(".gnb li").index(this);
            localStorage.setItem(storageKey, selectedIndex);
        });
    //});

};

scwin.menuInit = function() {//debugger;
    let jsonData = [];
    const isAsisInternalMenuUser = scwin.userClsCd == "01";

    // AS-IS top.jsp 기준: 내부사용자(01)만 상단 GNB 메뉴를 노출한다.
    if (!isAsisInternalMenuUser) {
        gen_menu1.hide();
        ds_menuTop.removeAll();
        return;
    }

    gen_menu1.show("");
    if(scwin.coClsCd == "0" || scwin.privAdmin == "T") {//동원로엑스 or 어드민
        jsonData = [
            { menuNm : "국제물류",engNm : "FORWARDING", menuId : "forwarding", lvl : "1",upperMenuId : "", actPgmScrPath : "",actPgmId : "",sysCd : "FW"},
            { menuNm : "물류",engNm : "LOGISTICS", menuId : "logistics", lvl : "1",upperMenuId : "", actPgmScrPath : "",actPgmId : "",sysCd : "DS"},
            { menuNm : "엔콜",engNm : "NCALL", menuId : "ncall", lvl : "1",upperMenuId : "", actPgmScrPath : "",actPgmId : "",sysCd : "NC"},
            { menuNm : "정비",engNm : "MAIN TENANCE", menuId : "maintenance", lvl : "1",upperMenuId : "", actPgmScrPath : "",actPgmId : "",sysCd : "EQ"},
            { menuNm : "회계",engNm : "ACCOUNT", menuId : "account", lvl : "1",upperMenuId : "", actPgmScrPath : "",actPgmId : "",sysCd : "AC"},
            { menuNm : "공통",engNm : "COMMON", menuId : "common", lvl : "1",upperMenuId : "", actPgmScrPath : "",actPgmId : "",sysCd : "CM"}
        ];
    } else if(scwin.coCd == "017") {//LA법인
        jsonData = [
            { menuNm : "회계",engNm : "ACCOUNT", menuId : "account", lvl : "1",upperMenuId : "", actPgmScrPath : "",actPgmId : "",sysCd : "LA"},
        ];
    } else if(scwin.userHomeClsCd == "FB" || scwin.userHomeClsCd == "81") {
        jsonData = [
            { menuNm : "엔콜",engNm : "NCALL", menuId : "ncall", lvl : "1",upperMenuId : "", actPgmScrPath : "",actPgmId : "",sysCd : "NC"},
        ];
    } else if(scwin.coClsCd == "1") { //자회사
         jsonData = [
            { menuNm : "물류",engNm : "LOGISTICS", menuId : "logistics", lvl : "1",upperMenuId : "", actPgmScrPath : "",actPgmId : "",sysCd : "JL"},
            // { menuNm : "엔콜",engNm : "NCALL", menuId : "ncall", lvl : "1",upperMenuId : "", actPgmScrPath : "",actPgmId : "",sysCd : "NC"},
            { menuNm : "회계",engNm : "ACCOUNT", menuId : "account", lvl : "1",upperMenuId : "", actPgmScrPath : "",actPgmId : "",sysCd : "SA"},
        ];
    } else {
        jsonData = [	//내부사용자-협력업체
            { menuNm : "물류",engNm : "LOGISTICS", menuId : "logistics", lvl : "1",upperMenuId : "", actPgmScrPath : "",actPgmId : "",sysCd : "DS"},
            { menuNm : "엔콜",engNm : "NCALL", menuId : "ncall", lvl : "1",upperMenuId : "", actPgmScrPath : "",actPgmId : "",sysCd : "NC"},
        ];
    }

    // 로컬에서만 사용
    scwin.smpData = [
        // { menuNm : "샘플",engNm : "SAMPLE", menuId : "sample", lvl : "1",upperMenuId : "", actPgmScrPath : "",actPgmId : ""},
        { menuNm : "샘플",engNm : "W SAMPLE", menuId : "wsample", lvl : "2",upperMenuId : "sample", actPgmScrPath : "",actPgmId : ""},
        { menuNm : "웹스퀘어 샘플",engNm : "SAMPLE", menuId : "smpList", lvl : "3",upperMenuId : "wsample", actPgmScrPath : "",actPgmId : ""},
        { menuNm : "기본 샘플",engNm : "", menuId : "smp0001", lvl : "4",upperMenuId : "smpList", actPgmScrPath : "/ui/sample/",actPgmId : "smp_comp.xml"},
        { menuNm : "탭관련 샘플",engNm : "", menuId : "smp0002", lvl : "4",upperMenuId : "smpList", actPgmScrPath : "/ui/sample/",actPgmId : "smp_tab.xml"},
        { menuNm : "피봇 샘플",engNm : "", menuId : "smp0003", lvl : "4",upperMenuId : "smpList", actPgmScrPath : "/ui/sample/",actPgmId : "smp_pivot.xml"},
        { menuNm : "wframe 샘플",engNm : "", menuId : "smp0004", lvl : "4",upperMenuId : "smpList", actPgmScrPath : "/ui/sample/",actPgmId : "smp_wframe.xml"},
        { menuNm : "그리드컬럼 동적변경 샘플",engNm : "", menuId : "smp0005", lvl : "4",upperMenuId : "smpList", actPgmScrPath : "/ui/sample/",actPgmId : "smp_gridInputTypeCustom.xml"},
        { menuNm : "합계 샘플",engNm : "", menuId : "smp0006", lvl : "4",upperMenuId : "smpList", actPgmScrPath : "/ui/sample/",actPgmId : "smp_merge.xml"},
        { menuNm : "공통 코드 샘플",engNm : "", menuId : "smp0007", lvl : "4",upperMenuId : "smpList", actPgmScrPath : "/ui/sample/",actPgmId : "smp_comp_comCode.xml"},
        { menuNm : "오즈 리포트 샘플",engNm : "", menuId : "smp0008", lvl : "4",upperMenuId : "smpList", actPgmScrPath : "/ui/sample/",actPgmId : "ozreportpage.xml"},
        { menuNm : "파일업로드 샘플",engNm : "", menuId : "smp0009", lvl : "4",upperMenuId : "smpList", actPgmScrPath : "/ui/sample/",actPgmId : "smp_upload.xml"},
        { menuNm : "파일업로드 미리보기 샘플",engNm : "", menuId : "smp0019", lvl : "4",upperMenuId : "smpList", actPgmScrPath : "/ui/sample/",actPgmId : "smp_uploadPreview.xml"},
        { menuNm : "스케쥴달력 샘플",engNm : "", menuId : "smp0010", lvl : "4",upperMenuId : "smpList", actPgmScrPath : "/ui/sample/",actPgmId : "smp_scheduleCalendar.xml"},
        { menuNm : "GroupBy 샘플",engNm : "", menuId : "smp0011", lvl : "4",upperMenuId : "smpList", actPgmScrPath : "/ui/sample/",actPgmId : "smp_groupBy.xml"},
        { menuNm : "페이징 샘플",engNm : "", menuId : "smp0012", lvl : "4",upperMenuId : "smpList", actPgmScrPath : "/ui/sample/",actPgmId : "smp_pagelist.xml"},
        { menuNm : "멀티엑셀다운 샘플",engNm : "", menuId : "smp0013", lvl : "4",upperMenuId : "smpList", actPgmScrPath : "/ui/sample/",actPgmId : "smp_multiExcelDownload.xml"},
        { menuNm : "그리드 동적생성 샘플",engNm : "", menuId : "smp0014", lvl : "4",upperMenuId : "smpList", actPgmScrPath : "/ui/sample/",actPgmId : "smp_dynamicGrid.xml"},
        { menuNm : "공통 샘플",engNm : "C SAMPLE", menuId : "csample", lvl : "3",upperMenuId : "sample", actPgmScrPath : "",actPgmId : ""},
        { menuNm : "고정자산종류관리",engNm : "C SAMPLE", menuId : "fi_100_08_02b", lvl : "4",upperMenuId : "sample", actPgmScrPath : "/ui/ac/fi/fixedaset/",actPgmId : "fi_100_08_02b.jsp"},
        { menuNm : "컨테이너 하불 매입 승인",engNm : "C SAMPLE", menuId : "fs_102_01_11b", lvl : "4",upperMenuId : "sample", actPgmScrPath : "/ui/ds/fs/adjm/",actPgmId : "fs_102_01_11b.jsp"},
        { menuNm : "일용직기본등록",engNm : "C SAMPLE", menuId : "fi_405_01_01b", lvl : "4",upperMenuId : "sample", actPgmScrPath : "/ui/ac/fi/taxbiz/tempjob/",actPgmId : "fi_405_01_01b.jsp"},
        { menuNm : "협력업체 세금계산서 발행",engNm : "C SAMPLE", menuId : "fs_103_03_01b", lvl : "4",upperMenuId : "sample", actPgmScrPath : "/ui/ds/fs/adjm/",actPgmId : "fs_103_03_01b.jsp"},
        { menuNm : "퍼블",engNm : "", menuId : "pubMain", lvl : "2",upperMenuId : "sample", actPgmScrPath : "",actPgmId : ""},
        { menuNm : "PAGE",engNm : "", menuId : "pubpage", lvl : "3",upperMenuId : "pubMain", actPgmScrPath : "",actPgmId : ""},
        { menuNm : "국제물류",engNm : "", menuId : "pubpage6", lvl : "4",upperMenuId : "pubpage", actPgmScrPath : "/pub/",actPgmId : "page6.xml"},
        { menuNm : "물류",engNm : "", menuId : "pubpage1", lvl : "4",upperMenuId : "pubpage", actPgmScrPath : "/pub/",actPgmId : "page1.xml"},
        { menuNm : "회계",engNm : "", menuId : "pubpage2", lvl : "4",upperMenuId : "pubpage", actPgmScrPath : "/pub/",actPgmId : "page2.xml"},
        { menuNm : "정비",engNm : "", menuId : "pubpage3", lvl : "4",upperMenuId : "pubpage", actPgmScrPath : "/pub/",actPgmId : "page3.xml"},
        { menuNm : "엔콜",engNm : "", menuId : "pubpage5", lvl : "4",upperMenuId : "pubpage", actPgmScrPath : "/pub/",actPgmId : "page4.xml"},
        { menuNm : "공통",engNm : "", menuId : "pubpage4", lvl : "4",upperMenuId : "pubpage", actPgmScrPath : "/pub/",actPgmId : "page5.xml"},        
        { menuNm : "COMPONENT",engNm : "", menuId : "pubcomp", lvl : "3",upperMenuId : "pubMain", actPgmScrPath : "",actPgmId : ""},
        { menuNm : "가이드",engNm : "", menuId : "pubcomp", lvl : "4",upperMenuId : "pubMain", actPgmScrPath : "/pub/",actPgmId : "guide.xml"},
        { menuNm : "화면샘플",engNm : "", menuId : "pubsample", lvl : "3",upperMenuId : "pubMain", actPgmScrPath : "",actPgmId : ""},
        { menuNm : "화면샘플01",engNm : "", menuId : "pubsample", lvl : "4",upperMenuId : "pubMain", actPgmScrPath : "/pub/",actPgmId : "sample_default.xml"},
        { menuNm : "화면샘플01",engNm : "", menuId : "pubsample", lvl : "4",upperMenuId : "pubMain", actPgmScrPath : "/pub/",actPgmId : "sample.xml"}
    ];

    // local/개발 에서만 샘플메뉴 보이기
    if(location.host.indexOf("newdevdebis") > -1 || location.host.indexOf("localhost") > -1 ||  location.host.indexOf("127.0.0.1") > -1 ) { // 로컬일때
        jsonData.push({ menuNm : "샘플",engNm : "SAMPLE", menuId : "sample", lvl : "1",upperMenuId : "", actPgmScrPath : "",actPgmId : "",sysCd : "SP"} );
        ed_searchIpt.show("");
    }
    if(location.host.indexOf("newdebis") > -1 ) {
        quickBtnArea.show("");
    }

    ds_menuTop.setJSON(jsonData); // 상단메뉴 데이터 셋팅

    let idx, rowDt , menuNm, engNm, menuId, sysCd;
    for(let i=0; i < ds_menuTop.getRowCount(); i++) {//debugger;
        idx = gen_menu1.insertChild(i);

        menuNm = ds_menuTop.getCellData(i, "menuNm");
        engNm =  ds_menuTop.getCellData(i, "engNm");
        menuId = ds_menuTop.getCellData(i, "menuId");
        sysCd = ds_menuTop.getCellData(i, "sysCd");
        if(sysCd == scwin.sysCd) {
            gen_menu1.getChild(idx, "grp_m1").addClass("on");
        }
        else if(!isAsisInternalMenuUser && (scwin.userHomeClsCd == "FB" || scwin.userHomeClsCd == "81")){
            gen_menu1.getChild(0, "grp_m1").addClass("on"); // FB 또는 81일 떄 엔콜(첫번째 값에) 파란색 넣어줌
        }

        gen_menu1.getChild(idx, "tbx_kVal").setValue(menuNm);
        gen_menu1.getChild(idx, "tbx_eVal").setValue(engNm);
        gen_menu1.getChild(idx, "tbx_kVal").setUserData("menuId", menuId);
        gen_menu1.getChild(idx, "tbx_kVal").setUserData("sysCd", sysCd);

        // 1depth 메뉴 클릭
        gen_menu1.getChild(idx, "grp_m1").bind("click", function() {//debugger;
            var sysCd = gen_menu1.getChild(this.getGeneratedIndex(),"tbx_kVal").getUserData("sysCd");
            var upperMenuId = gen_menu1.getChild(this.getGeneratedIndex(),"tbx_kVal").getUserData("menuId");
            var sideWin = $p.top().wfm_side.getWindow();
            $p.top().wfm_side.getWindow().tac_tabControl1.setSelectedTabIndex(0); // 좌측 탭메뉴 변경
            if(sysCd == "SP") { // 샘플일때
                var filteredSampleMenu = sideWin.scwin.filterSubCompanyNcallMenu(scwin.smpData);
                sideWin.ds_trvMenu.setJSON(filteredSampleMenu);
                sideWin.ds_originTrvMenu.setJSON(filteredSampleMenu);
            } 
            else if(sysCd == "NC"){
                dma_userParam.set("systemClsCd", "NTIS");
                dma_userParam.set("sysCd", "NC");
                $c.sbm.execute(sbm_getMenuList);
            }
            else {
                // 매번 조회로 수정 DT요청 2026-0401
               // if(scwin.menuData[sysCd] && scwin.menuData[sysCd].length > 0) { // 데이터가 있을때
                    var filteredMenuData = sideWin.scwin.filterSubCompanyNcallMenu(scwin.menuData[sysCd]);
                    sideWin.ds_trvMenu.setJSON(filteredMenuData);
                    sideWin.ds_originTrvMenu.setJSON(filteredMenuData);
               // } else {
                    dma_userParam.set("systemClsCd", "");
                    dma_userParam.set("sysCd", sysCd);
                    $c.sbm.execute(sbm_getMenuList); // 좌측 메뉴데이터 조회
                //}
            };
        });
    }
};

scwin.ed_input1_oneditenter = async function () {//debugger;
    let src = ed_searchIpt.getValue();
    let url = src.replace(/\\/g, "/");
    let pgmId = url.substring(url.lastIndexOf("/")+1);
    let fNm = pgmId.substring(0, pgmId.lastIndexOf("."));
    let obj = $p.top().ds_allMenuList.getMatchedJSON("actPgmId", fNm, false);
    let menuNm = obj[0] ? obj[0].menuNm : pgmId;
    $c.win.openMenu(menuNm, src, pgmId, null, { authBypassYn : "Y" });

};
scwin.autoPopupCount = 0;
scwin.sbm_getMenuList_submitdone = async function (e) {//debugger;
    var sysCd = dma_userParam.get("sysCd");

    scwin.menuData[sysCd] = e.responseJSON.GAUCE;
    for (const row of scwin.menuData[sysCd]) {
        switch (row.actPgmId) {
            case "op_304_01_01b.jsp":
                row.actPgmScrPath = "/ds/op/wrkrslts/transwrkrslts/";
                break;
            case "op_304_01_02b.jsp":
                row.actPgmScrPath = "/ds/op/wrkrslts/transwrkrslts/";
                break;
            case "as_102_01_02b.jsp":
                row.actPgmScrPath = "/ds/as/cstmrsrvc/coafmgnt/";
                break;
            case "as_102_01_03b.jsp":
                row.actPgmScrPath = "/ds/as/cstmrsrvc/coafmgnt/";
                break;
            case "op_301_01_05b.jsp":
                if(row.menuId.indexOf("n") !== -1){
                    row.actPgmId = "op_301_01_19b.jsp"; //반입등록
                }
                break;
            case "op_301_01_06b.jsp":
                if(row.menuId.indexOf("n") !== -1){
                    row.actPgmId = "op_301_01_09b.jsp"; //반출등록
                }
                break;
            case "op_304_01_06b.jsp":
                row.actPgmScrPath = "/ds/op/wrkrslts/transwrkrslts/";
                break;
            case "fs_103_03_01b.jsp":
                if(row.menuId.indexOf("n") !== -1){
                    row.actPgmId = "fs_103_03_02b.jsp"; //협력업체 세금계산서 발행
                }
                break;
            case "op_204_04_01b.jsp":
                if(row.menuId.indexOf("n") !== -1){
                    row.actPgmScrPath = "/tn/op/transwrkindict/cntr/";
                    row.actPgmId = "tn_304_03_09b.jsp"; //CY구역관리
                }
                break;
            case "op_301_01_17b.jsp":
                if(row.menuId.indexOf("n") !== -1){
                    row.actPgmId = "op_301_01_20b.jsp"; //반출입 정보 수정
                }
                break;
            case "op_304_01_65b.jsp":
                if(row.menuId.indexOf("n") !== -1){
                    row.actPgmScrPath = "/tn/op/transwrkindict/cntr/";
                    row.actPgmId = "tn_304_01_12b.jsp"; //출도착등록(컨테이너)(협럭업체용)
                }
                break;
            case "op_202_02_07b.jsp":
                if(row.menuId.indexOf("n") !== -1){
                    row.actPgmId = "op_202_02_08b.jsp"; //셔틀운송작업물량차량조회
                }
                break;
            case "sd_402_01_35t.jsp":
                if(row.menuId.indexOf("n") !== -1){
                    row.actPgmId = "sd_402_01_35b.jsp"; //오더요청등록(크나우프)
                }
                break;

        }
    }
    if (scwin.autoPopupCount < 1) {
        $c.data.cfAutoPopUpRun("1200","610","1","retrieveExpireContractCnt","/ui/ds/sd/salesactiv/ctrtmgnt/sd_202_01_52b.xml",$c.data.getMemInfo().userId);
        $c.data.cfAutoPopUpRun("1200","610","1","retrieveExpireContractCnt","/ui/ds/sd/salesactiv/ctrtmgnt/sd_202_01_53b.xml",$c.data.getMemInfo().userId);

        // 계약만료 알림
        WebSquare.cookie.setCookie("retrieveExpireContractCnt2", "false");
        $c.data.cfAutoPopUpRun("1200","620","1","retrieveExpireContractCnt2","/ui/cm/bc/rentloan/zz_900_01_09b.xml",$c.data.getMemInfo().userId);

        $c.data.cfAutoPopUpRun("1200","610","1","retrieveClntInfoPopUpCnt","/ui/tn/cs/clntmgnt/tn_200_01_03b.xml",$c.data.getMemInfo().userId,"NcallCommonEBC");
        // 팝업호출
        if ($c.data.getMemInfo().lobranCd == "1GG") {
            let pSQLID   = "retrieveAccountReceivableOverDayEachPresentCondition";
            let pCallURL = "/ui/ac/fm/acctrecvmgnt/acctrecvcontmgnt/fm_603_08_01b.xml";
            let pExpDay  = "1";
            let pW       = 1200;
            let pH       = 610;

            // localStorage 체크
            let saved = WebSquare.localStorage.getItem(pSQLID);
            let isBlocked = false;

            if (saved) {
                if (Number(saved) > new Date().getTime()) {
                    isBlocked = true;
                }
            }

            if (!isBlocked) {
                let now = new Date();
                let winName = now.getHours().toString()
                            + now.getMinutes().toString()
                            + now.getSeconds().toString();

                let data = {
                    pCookieID: pSQLID,
                    pCallURL: pCallURL,
                    pExpDay: pExpDay
                };

                let opts = {
                    id: winName,
                    popupName: "초과채권 거래처",
                    width: pW,
                    height: pH,
                    type: "browserPopup"
                };

                $c.win.openPopup("/ui/cm/bc/rentloan/AutoPopUp.xml", opts, data);
            }
        }

        scwin.autoPopupCount++;
    }

    const sideWin = $p.top().wfm_side.getWindow();
    const filteredMenuData = sideWin.scwin.filterSubCompanyNcallMenu(scwin.menuData[sysCd]);
    sideWin.ds_trvMenu.setJSON(filteredMenuData);
    sideWin.ds_originTrvMenu.setJSON(filteredMenuData);
};

