scwin.f_base64Encode = function(str, types){

    // var str = "290060"; //로그인한 ID 정보 
    var enc64List = [];
	    for (var i = 0; i < 26; i++) enc64List.push(String.fromCharCode(65 + i));
	    for (var i = 0; i < 26; i++) enc64List.push(String.fromCharCode(97 + i));
	    for (var i = 0; i < 10; i++) enc64List.push(String.fromCharCode(48 + i));
	    enc64List.push("+");
	    enc64List.push("/");

	    var output = "";
	    var i = 0;
	    while (i < str.length) {
	        var c1 = str.charCodeAt(i++);
	        var c2 = i < str.length ? str.charCodeAt(i++) : NaN;
	        var c3 = i < str.length ? str.charCodeAt(i++) : NaN;

	        var e1 = c1 >> 2;
	        var e2 = ((c1 & 3) << 4) | ((c2 || 0) >> 4);
	        var e3 = ((c2 & 15) << 2) | ((c3 || 0) >> 6);
	        var e4 = c3 & 63;

	        output += enc64List[e1];
	        output += enc64List[e2];
	        output += isNaN(c2) ? "=" : enc64List[e3];
	        output += isNaN(c3) ? "=" : enc64List[e4];
	    }

    var sURL = "http://58.120.165.89:7080/xclick_auth_link.jsp?prog_id="+types+"&ssoId=" +output ; //debia asis 운영서버로 자동로그인 호출
	console.log("===str : " + str);
    console.log("===sURL : " + sURL);
	window.open(sURL, '_blank');

	   // return output;
};
